import { readFileSync, writeFileSync } from "node:fs";

const migrations = [
  "0001_durable_foundation",
  "0002_durable_invariants",
  "0003_artifact_lifecycle",
  "0004_queue_delivery",
  "0005_governance_lifecycle",
  "0006_backup_restore",
  "0007_identity_github_authorization",
].map((id) => ({
  id,
  sql: readFileSync(
    new URL(`../src/infrastructure/postgres/migrations/${id}.sql`, import.meta.url),
    "utf8",
  ).replace(/\r\n?/g, "\n"),
}));

const output = [
  "// Generated by scripts/generate-migration-manifest.mjs. Do not edit.",
  "// Runtime routes import this static module so Next.js traces only the migration assets.",
  `export const POSTGRES_MIGRATION_SOURCES = ${JSON.stringify(migrations, null, 2)} as const;`,
  "",
].join("\n");

writeFileSync(
  new URL(
    "../src/infrastructure/postgres/migration-manifest.generated.ts",
    import.meta.url,
  ),
  output,
);
